    86→export class KspecAdapter implements TaskAdapter {
    87→  readonly kind = 'kspec' as const
    88→
    89→  // Per-instance daemon state (avoids cross-instance interference from module-level globals)
    90→  _daemonEnsuredFlag = true
    91→  private _daemonEnsuredForCwd: string | null = null
    92→
    93→  private async ensureDaemon(cwd: string): Promise<boolean> {
    94→    // Reset flag when switching projects so we re-verify daemon for new cwd
    95→    if (this._daemonEnsuredForCwd !== null && this._daemonEnsuredForCwd !== cwd) {
    96→      this._daemonEnsuredFlag = false
    97→    }
    98→
    99→    // Quick health check first
   100→    try {
   101→      const res = await fetch(`${API_BASE}/api/health`)
   102→      if (res.ok) { this._daemonEnsuredFlag = true; this._daemonEnsuredForCwd = cwd; return true }
   103→    } catch { /* daemon not running */ }
   104→
   105→    // Start daemon via IPC (always attempt if health check failed)
   106→    const result = await window.electronAPI?.kspecEnsureDaemon?.(cwd)
   107→    if (result?.success) { this._daemonEnsuredFlag = true; this._daemonEnsuredForCwd = cwd; return true }
   108→    return false
   109→  }
   110→
   111→  async check(cwd: string): Promise<BackendStatus> {
   112→    // Check if .kspec/ exists via IPC (filesystem check)
   113→    const hasKspec = await window.electronAPI?.kspecCheck?.(cwd)
   114→    if (!hasKspec?.exists) {
