   127→
   128→  async list(cwd: string): Promise<UnifiedTask[]> {
   129→    try {
   130→      const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd, undefined, this)
   131→      return (data.items ?? []).map(toUnified)
   132→    } catch {
   133→      // Daemon might not be running — try to start it and retry once
   134→      const started = await this.ensureDaemon(cwd)
   135→      if (started) {
   136→        try {
   137→          const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd, undefined, this)
   138→          return (data.items ?? []).map(toUnified)
   139→        } catch { /* still failed */ }
   140→      }
   141→      return []
   142→    }
   143→  }
   144→
   145→  async show(cwd: string, taskId: string): Promise<UnifiedTask | null> {
   146→    try {
   147→      const data = await api<Record<string, unknown>>('GET', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, undefined, this)
   148→      return toUnified(data)
   149→    } catch {
   150→      return null
   151→    }
   152→  }
   153→
   154→  async create(cwd: string, params: CreateTaskParams): Promise<{ success: boolean; error?: string }> {
   155→    try {
   156→      await api('POST', '/api/tasks', cwd, {
   157→        title: params.title,
   158→        description: params.description,
   159→        priority: params.priority,
