   168→  }
   169→
   170→  async start(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
   171→    try {
   172→      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/start`, cwd, undefined, this)
   173→      return { success: true }
   174→    } catch (e) {
   175→      return { success: false, error: String(e) }
   176→    }
   177→  }
   178→
   179→  async complete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
   180→    try {
   181→      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/complete`, cwd, undefined, this)
   182→      return { success: true }
   183→    } catch (e) {
   184→      return { success: false, error: String(e) }
   185→    }
   186→  }
   187→
   188→  async delete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
   189→    try {
   190→      await api('DELETE', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, undefined, this)
   191→      return { success: true }
   192→    } catch (e) {
   193→      return { success: false, error: String(e) }
   194→    }
   195→  }
   196→
   197→  async update(cwd: string, taskId: string, params: UpdateTaskParams): Promise<{ success: boolean; error?: string }> {
   198→    try {
   199→      // Map unified status names back to kspec native status names
   200→      const body = { ...params }
   201→      if (body.status === 'open') body.status = 'pending' as TaskStatus
   202→      if (body.status === 'closed') body.status = 'completed' as TaskStatus
   203→      await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, body, this)
   204→      return { success: true }
