   206→      return { success: false, error: String(e) }
   207→    }
   208→  }
   209→
   210→  async cycleStatus(cwd: string, taskId: string, currentStatus: TaskStatus): Promise<{ success: boolean; error?: string }> {
   211→    switch (currentStatus) {
   212→      case 'open': return this.start(cwd, taskId)
   213→      case 'in_progress': return this.complete(cwd, taskId)
   214→      default:
   215→        // Kspec uses 'pending' internally — 'open' is only the unified status
   216→        try {
   217→          await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, { status: 'pending' }, this)
   218→          return { success: true }
   219→        } catch (e) {
   220→          return { success: false, error: String(e) }
   221→        }
   222→    }
   223→  }
