/**
 * WebSocket Manager - WebSocket handling
 */

import { WebSocket, WebSocketServer } from 'ws'
import { Server } from 'http'
import { log } from './utils'
import { PendingFile } from './types'

export interface WebSocketManagerDeps {
  getToken: () => string
  getPtyManager: () => any
  getPort: () => number
  getTerminalSubscriptions: () => Map<string, Set<WebSocket>>
  getPtyStreams: () => Map<string, Set<WebSocket>>
  getPtyDataBuffer: () => Map<string, string[]>
  getConnectedClients: () => Set<WebSocket>
  getPendingFiles: () => Map<string, PendingFile>
}

export function setupWebSocket(server: Server, deps: WebSocketManagerDeps): WebSocketServer {
  const wss = new WebSocketServer({ noServer: true })

  // Handle upgrade requests manually to support multiple paths
  server.on('upgrade', (req, socket, head) => {
    const url = new URL(req.url || '', `http://localhost:${deps.getPort()}`)
    const pathname = url.pathname

    // Get token from Sec-WebSocket-Protocol header (preferred) or query string (fallback)
    const protocolHeader = req.headers['sec-websocket-protocol'] as string | undefined
    const protocols = protocolHeader?.split(',').map(p => p.trim()) || []
    const tokenFromProtocol = protocols.find(p => p.startsWith('token-'))?.slice(6)
    const tokenFromQuery = url.searchParams.get('token')
    const token = tokenFromProtocol || tokenFromQuery

    log('WebSocket upgrade request', {
      url: req.url,
      pathname,
      hasProtocolToken: !!tokenFromProtocol,
      hasQueryToken: !!tokenFromQuery,
      headers: {
        host: req.headers.host,
        origin: req.headers.origin,
        upgrade: req.headers.upgrade
      }
    })

    // Validate token for all WebSocket connections
    if (token !== deps.getToken()) {
      log('WebSocket auth failed', { providedToken: token?.slice(0, 8) })
      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n')
      socket.destroy()
      return
    }

    // Handle PTY stream WebSocket: /api/pty/:id/stream
    const ptyStreamMatch = pathname.match(/^\/api\/pty\/([^/]+)\/stream$/)
    if (ptyStreamMatch) {
      const ptyId = ptyStreamMatch[1]
      handlePtyStreamUpgrade(req, socket, head, ptyId, deps)
      return
    }

    // Handle main WebSocket path: /ws
    if (pathname === '/ws') {
      wss.handleUpgrade(req, socket, head, (ws) => {
        wss.emit('connection', ws, req)
      })
      return
    }

    // Unknown WebSocket path
    log('Unknown WebSocket path', { pathname })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
  })

  wss.on('connection', (ws: WebSocket, _req) => {
    log('WebSocket client connected (main)')

    deps.getConnectedClients().add(ws)

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())
        handleWebSocketMessage(ws, msg, deps)
      } catch (e) {
        log('Invalid WebSocket message', { error: String(e) })
      }
    })

    ws.on('close', () => {
      deps.getConnectedClients().delete(ws)

      deps.getTerminalSubscriptions().forEach((subscribers, ptyId) => {
        subscribers.delete(ws)
        if (subscribers.size === 0) {
          deps.getTerminalSubscriptions().delete(ptyId)
        }
      })
      log('WebSocket client disconnected (main)')
    })

    // Send welcome message
    ws.send(JSON.stringify({ type: 'connected', timestamp: Date.now() }))

    // Send any pending files to new client
    sendPendingFilesToClient(ws, deps.getPendingFiles())
  })

  return wss
}

function handlePtyStreamUpgrade(
  req: any,
  socket: any,
  head: any,
  ptyId: string,
  deps: WebSocketManagerDeps
): void {
  const ptyManager = deps.getPtyManager()
  if (!ptyManager || !ptyManager.getProcess(ptyId)) {
    log('PTY stream upgrade failed - PTY not found', { ptyId })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
    return
  }

  const streamWss = new WebSocketServer({ noServer: true })

  streamWss.handleUpgrade(req, socket, head, (ws) => {
    log('PTY stream connected', { ptyId })

    const ptyStreams = deps.getPtyStreams()
    if (!ptyStreams.has(ptyId)) {
      ptyStreams.set(ptyId, new Set())
    }
    ptyStreams.get(ptyId)!.add(ws)

    ws.send(JSON.stringify({ type: 'connected', ptyId }))

    // Flush any buffered data
    flushPtyBuffer(ptyId, ws, deps.getPtyDataBuffer())

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())

        switch (msg.type) {
          case 'input':
            if (msg.data && ptyManager) {
              ptyManager.write(ptyId, msg.data)
            }
            break

          case 'resize':
            if (msg.cols && msg.rows && ptyManager) {
              ptyManager.resize(ptyId, msg.cols, msg.rows)
            }
            break

          case 'ping':
            ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
            break

          default:
            log('Unknown PTY stream message type', { type: msg.type, ptyId })
        }
      } catch (e) {
        log('Invalid PTY stream message', { error: String(e), ptyId })
      }
    })

    ws.on('close', () => {
      log('PTY stream disconnected', { ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
      if (ptyStreams.get(ptyId)?.size === 0) {
        ptyStreams.delete(ptyId)
      }
    })

    ws.on('error', (err) => {
      log('PTY stream error', { error: String(err), ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
    })
  })
}

function handleWebSocketMessage(ws: WebSocket, msg: any, deps: WebSocketManagerDeps): void {
  const ptyManager = deps.getPtyManager()
  const terminalSubscriptions = deps.getTerminalSubscriptions()

  switch (msg.type) {
    case 'subscribe':
      if (msg.ptyId) {
        if (!terminalSubscriptions.has(msg.ptyId)) {
          terminalSubscriptions.set(msg.ptyId, new Set())
        }
        terminalSubscriptions.get(msg.ptyId)!.add(ws)
        ws.send(JSON.stringify({ type: 'subscribed', ptyId: msg.ptyId }))
      }
      break

    case 'unsubscribe':
      if (msg.ptyId) {
        terminalSubscriptions.get(msg.ptyId)?.delete(ws)
      }
      break

    case 'write':
      if (msg.ptyId && msg.data && ptyManager) {
        ptyManager.write(msg.ptyId, msg.data)
      }
      break

    case 'resize':
      if (msg.ptyId && msg.cols && msg.rows && ptyManager) {
        ptyManager.resize(msg.ptyId, msg.cols, msg.rows)
      }
      break

    case 'ping':
      ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
      break
  }
}

function flushPtyBuffer(ptyId: string, ws: WebSocket, ptyDataBuffer: Map<string, string[]>): void {
  const buffer = ptyDataBuffer.get(ptyId)
  if (!buffer || buffer.length === 0) return

  buffer.forEach(data => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type: 'data', data }))
    }
  })

  ptyDataBuffer.delete(ptyId)
}

function sendPendingFilesToClient(ws: WebSocket, pendingFiles: Map<string, PendingFile>): void {
  const now = Date.now()
  // Clean up expired files first
  for (const [fileId, file] of pendingFiles) {
    if (file.expiresAt < now) {
      pendingFiles.delete(fileId)
    }
  }

  const files = Array.from(pendingFiles.values()).map(f => ({
    id: f.id,
    name: f.name,
    size: f.size,
    mimeType: f.mimeType,
    message: f.message
  }))

  if (files.length > 0) {
    ws.send(JSON.stringify({ type: 'files:pending', files }))
  }
}

export function broadcastTerminalData(
  ptyId: string,
  data: string,
  terminalSubscriptions: Map<string, Set<WebSocket>>
): void {
  const subscribers = terminalSubscriptions.get(ptyId)
  if (!subscribers) return

  const message = JSON.stringify({
    type: 'terminal-data',
    ptyId,
    data
  })

  subscribers.forEach(ws => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message)
    }
  })
}

export function broadcastPtyData(
  ptyId: string,
  data: string,
  ptyStreams: Map<string, Set<WebSocket>>,
  ptyDataBuffer: Map<string, string[]>
): void {
  const streams = ptyStreams.get(ptyId)

  // If no streams connected, buffer the data
  if (!streams || streams.size === 0) {
    if (!ptyDataBuffer.has(ptyId)) {
      ptyDataBuffer.set(ptyId, [])
    }
    const buffer = ptyDataBuffer.get(ptyId)!
    buffer.push(data)
    // Limit buffer size
    if (buffer.length > 1000) {
      buffer.shift()
    }
    return
  }

  const message = JSON.stringify({
    type: 'data',
    data
  })

  streams.forEach(ws => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message)
    }
  })
}

export function broadcastPtyExit(
  ptyId: string,
  code: number,
  ptyStreams: Map<string, Set<WebSocket>>,
  terminalSubscriptions?: Map<string, Set<WebSocket>>,
  ptyDataBuffer?: Map<string, string[]>
): void {
  const streams = ptyStreams.get(ptyId)
  if (streams && streams.size > 0) {
    const message = JSON.stringify({
      type: 'exit',
      code
    })

    streams.forEach(ws => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message)
        ws.close(1000, 'PTY exited')
      }
    })
  }

  // Clean up stale subscriptions and buffered data for this PTY
  ptyStreams.delete(ptyId)
  terminalSubscriptions?.delete(ptyId)
  ptyDataBuffer?.delete(ptyId)
}

/**
 * Mobile Server Middleware - CORS, auth, rate limiting
 */

import { Express, Request, Response, NextFunction } from 'express'
import cors from 'cors'
import express from 'express'
import { existsSync } from 'fs'
import {
  classifyIp,
  getClientIp,
  checkRateLimit,
  recordFailedAuth,
  clearRateLimit,
  checkEndpointRateLimit,
  IpClass
} from '../mobile-security'
import { log, isStaticPath } from './utils'
import { EndpointAccess } from './types'

export function setupCorsMiddleware(app: Express): void {
  app.use(cors({
    origin: (origin, callback) => {
      // Allow requests with no origin (same-origin, mobile apps, curl, etc.)
      if (!origin) {
        return callback(null, true)
      }

      // Allow capacitor:// and file:// schemes (mobile app)
      if (origin.startsWith('capacitor://') || origin.startsWith('file://')) {
        return callback(null, true)
      }

      // Parse origin to extract hostname for safe validation
      let hostname: string
      try {
        hostname = new URL(origin).hostname
      } catch {
        log('CORS blocked malformed origin', { origin })
        return callback(new Error('CORS not allowed for this origin'))
      }

      // Allow localhost variants
      if (hostname === 'localhost' || hostname === '127.0.0.1') {
        return callback(null, true)
      }

      // Allow local network IP ranges (RFC 1918)
      // 10.x.x.x, 192.168.x.x, 172.16-31.x.x
      const localNetworkPattern = /^(10\.\d+\.\d+\.\d+|192\.168\.\d+\.\d+|172\.(1[6-9]|2\d|3[01])\.\d+\.\d+)$/
      if (localNetworkPattern.test(hostname)) {
        return callback(null, true)
      }

      // Allow Tailscale CGNAT range (100.64.0.0 - 100.127.255.255)
      const tailscaleCgnatPattern = /^100\.(6[4-9]|[7-9]\d|1[01]\d|12[0-7])\.\d+\.\d+$/
      if (tailscaleCgnatPattern.test(hostname)) {
        return callback(null, true)
      }

      // Allow Tailscale MagicDNS hostnames (*.ts.net)
      if (hostname.endsWith('.ts.net')) {
        return callback(null, true)
      }

      // Reject other origins
      log('CORS blocked origin', { origin })
      callback(new Error('CORS not allowed for this origin'))
    },
    credentials: true
  }))
}

export function setupStaticMiddleware(app: Express, rendererPath: string): void {
  log('Static files path:', { path: rendererPath, exists: existsSync(rendererPath) })
  if (existsSync(rendererPath)) {
    app.use(express.static(rendererPath, {
      index: 'index.html'
    }))
  }
}

export function setupJsonMiddleware(app: Express): void {
  app.use(express.json({ limit: '1mb' }))
}

export function setupRateLimitMiddleware(app: Express): void {
  app.use((req: Request, res: Response, next: NextFunction) => {
    const clientIp = getClientIp(req)
    const rateLimit = checkRateLimit(clientIp)

    if (!rateLimit.allowed) {
      return res.status(429).json({
        error: 'Too many failed attempts. Please try again later.',
        retryAfter: rateLimit.retryAfter
      }).setHeader('Retry-After', String(rateLimit.retryAfter || 900))
    }

    next()
  })
}

export function setupAuthMiddleware(app: Express, getToken: () => string): void {
  app.use((req: Request, res: Response, next: NextFunction) => {
    // Skip auth for unauthenticated endpoints
    if (req.path === '/health' || req.path === '/connect' || req.path === '/verify-handshake') {
      return next()
    }

    // /ws-test uses query string auth (validates token itself)
    if (req.path === '/ws-test') {
      const queryToken = req.query.token as string
      if (queryToken === getToken()) {
        return next()
      }
      // Let the route handler return the proper error
      return next()
    }
    // Skip auth for static files (token passed in query string for initial load)
    if (isStaticPath(req.path)) {
      const queryToken = req.query.token as string
      if (queryToken === getToken()) {
        return next()
      }
      // Check cookie for subsequent static file requests
      const cookieToken = req.headers.cookie?.split(';')
        .map(c => c.trim())
        .find(c => c.startsWith('ct_token='))
        ?.split('=')[1]
      if (cookieToken === getToken()) {
        return next()
      }
      // No valid token - still serve static files but without sensitive data
      return next()
    }

    const clientIp = getClientIp(req)

    // Allow query token for file downloads (needed for Android WebView window.open)
    if (req.path.startsWith('/api/files/')) {
      const queryToken = req.query.token as string
      if (queryToken === getToken()) {
        clearRateLimit(clientIp)
        return next()
      }
    }

    const authHeader = req.headers.authorization
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      recordFailedAuth(clientIp)
      return res.status(401).json({ error: 'Missing authorization header' })
    }

    const providedToken = authHeader.slice(7)
    if (providedToken !== getToken()) {
      const blocked = recordFailedAuth(clientIp)
      if (blocked) {
        return res.status(429).json({
          error: 'Too many failed attempts. Please try again later.',
          retryAfter: 900
        })
      }
      return res.status(403).json({ error: 'Invalid token' })
    }

    // Successful auth - clear rate limit
    clearRateLimit(clientIp)

    next()
  })
}

export function getEndpointAccessLevel(path: string, method: string): EndpointAccess {
  // Settings: GET is read (allows mobile to load theme), POST is admin-only
  if (path.includes('/api/settings')) {
    return method === 'GET' ? 'read' : 'admin'
  }

  // Terminal and write operations need write access
  if (path.includes('/api/terminal')) {
    return 'write'
  }

  // PTY operations need write access
  if (path.includes('/api/pty')) {
    return 'write'
  }

  // Workspace POST/PUT needs write, GET needs read
  if (path === '/api/workspace') {
    return method === 'GET' ? 'read' : 'write'
  }

  // Project add needs write access
  if (path === '/api/project/add') {
    return 'write'
  }

  // Sessions discovery is read-only
  if (path === '/api/sessions') {
    return 'read'
  }

  // Beads: GET operations are read, write operations need write access
  if (path.includes('/projects/beads')) {
    if (method === 'GET') {
      return 'read'
    }
    return 'write'
  }

  // TTS speak/stop/settings need write
  if (path.includes('/api/tts/speak') || path.includes('/api/tts/stop') || path.includes('/api/tts/settings')) {
    return 'write'
  }

  // File operations: restricted to local network for security
  if (path.includes('/api/files')) {
    return 'write'
  }

  // Default to read for other authenticated endpoints
  return 'read'
}

export function isAccessAllowed(ipClass: IpClass, access: EndpointAccess): boolean {
  switch (access) {
    case 'admin':
      return ipClass === 'localhost'
    case 'write':
      return ipClass === 'localhost' || ipClass === 'local_network'
    case 'read':
      return true
    default:
      return false
  }
}

export function setupIpAccessMiddleware(app: Express): void {
  app.use((req: Request, res: Response, next: NextFunction) => {
    // Skip for unauthenticated endpoints and static files
    if (req.path === '/health' || req.path === '/connect' || req.path === '/verify-handshake' || req.path === '/ws-test') {
      return next()
    }
    if (isStaticPath(req.path)) {
      return next()
    }

    const clientIp = getClientIp(req)
    const ipClass = classifyIp(clientIp)

    // Determine required access level for this endpoint
    const accessLevel = getEndpointAccessLevel(req.path, req.method)

    // Check if IP class is allowed for this access level
    if (!isAccessAllowed(ipClass, accessLevel)) {
      return res.status(403).json({
        error: `This operation requires ${accessLevel} access. Your IP (${ipClass}) is not authorized.`
      })
    }

    next()
  })
}

export function setupEndpointRateLimitMiddleware(app: Express): void {
  app.use((req: Request, res: Response, next: NextFunction) => {
    // Skip for health check, ws-test, and static files
    if (req.path === '/health' || req.path === '/ws-test' || isStaticPath(req.path)) {
      return next()
    }

    const clientIp = getClientIp(req)
    const result = checkEndpointRateLimit(clientIp, req.method, req.path)

    // Add rate limit headers
    res.setHeader('X-RateLimit-Remaining', String(result.remaining))
    res.setHeader('X-RateLimit-Reset', String(Math.ceil(result.resetIn / 1000)))

    if (!result.allowed) {
      return res.status(429).json({
        error: 'Too many requests. Please slow down.',
        retryAfter: Math.ceil(result.resetIn / 1000)
      }).setHeader('Retry-After', String(Math.ceil(result.resetIn / 1000)))
    }

    next()
  })
}

